const payload = $json;
const safety = payload.safety || {};
const intelligence = payload.intelligence || {};
const ocr = intelligence.ocr || {};
const failures = [];

if (payload.payload_type !== 'checkwise_local_pdf_metadata_dry_run') failures.push('unexpected payload_type');
if (!payload.metadata_rules_version) failures.push('missing metadata_rules_version');
if (!payload.document_type_code) failures.push('missing document_type_code');
if (payload.validation_result?.status !== 'passed') failures.push('validation did not pass');
if (safety.legal_approval_allowed !== false) failures.push('legal approval must be disabled');
if (safety.ai_used !== false) failures.push('AI must not run inside the backend dry-run');
if (safety.google_sheets_used !== false) failures.push('Google Sheets must not be written by the backend');
if (safety.external_services_used !== false) failures.push('external services must be disabled by the backend');
if (safety.human_review_required !== true) failures.push('human review must be required');
if (!intelligence.pdf_text_extraction) failures.push('missing pdf text extraction package');
if (!intelligence.ocr) failures.push('missing OCR status package');
if (!intelligence.ai_extraction_request) failures.push('missing AI extraction request package');
if (!intelligence.google_sheets?.row) failures.push('missing Google Sheets row package');
if (safety.ocr_used === true && !['completed', 'completed_no_text'].includes(ocr.status)) {
  failures.push('OCR safety flag is true but OCR did not complete');
}

if (failures.length) {
  throw new Error('Safety validation failed: ' + failures.join(', '));
}

return {
  json: {
    status: 'passed',
    checked_at: new Date().toISOString(),
    document_type_code: payload.document_type_code,
    metadata_rules_version: payload.metadata_rules_version,
    original_filename: payload.deterministic_file_metadata?.original_filename,
    sha256: payload.deterministic_file_metadata?.sha256,
    page_count: payload.deterministic_file_metadata?.page_count,
    review_item_count: payload.review_item_count,
    prefilled_review_fields: payload.review_items
      .filter((item) => item.status !== 'pending')
      .map((item) => item.field_key),
    pending_review_fields: payload.review_items
      .filter((item) => item.status === 'pending')
      .map((item) => item.field_key),
    pdf_text_extraction: intelligence.pdf_text_extraction,
    ocr_status: intelligence.ocr,
    ai_extraction_request: intelligence.ai_extraction_request,
    google_sheets_row: intelligence.google_sheets.row,
    safety,
    review_payload: payload
  }
};

const ocr = $json.ocr_status || {};
return {
  json: {
    ...$json,
    workflow_stage: 'backend_payload_validated_ocr_ready',
    ocr_summary: {
      used: ocr.ocr_used === true,
      status: ocr.status || 'missing',
      engine: ocr.engine || null,
      language: ocr.language || null,
      text_char_count: ocr.text_char_count || 0,
      sample: ocr.text_sample || null,
    },
  },
};

const request = $json.ai_extraction_request;
if (!request) {
  throw new Error('Missing ai_extraction_request from CheckWise backend payload.');
}

return {
  json: {
    ...$json,
    claude_request: {
      system_prompt: request.system_prompt,
      user_prompt: JSON.stringify(request.user_payload, null, 2),
      status: 'ready_for_claude_http_request',
    },
  },
};

const response = $json.claude_response || $json;
const blocks = Array.isArray(response.content) ? response.content : [];
const content = blocks
  .map((block) => block?.text || '')
  .filter(Boolean)
  .join('
')
  || response.message?.content
  || response.text
  || '';

let parsed = null;
let parseStatus = 'empty';
let parseError = null;

if (content) {
  try {
    parsed = JSON.parse(content);
    parseStatus = 'parsed_json';
  } catch (error) {
    parseStatus = 'raw_text_needs_review';
    parseError = error.message;
  }
}

return {
  json: {
    ...$json,
    ai_provider: 'anthropic_claude',
    ai_used: true,
    ai_parse_status: parseStatus,
    ai_parse_error: parseError,
    ai_raw_response: content,
    ai_suggestions: parsed,
    human_review_required: true,
    legal_approval_allowed: false,
  },
};

const row = $json.google_sheets_row || {};
const ocr = $json.ocr_status || {};

return {
  json: {
    ...row,
    ai_provider: $json.ai_provider || 'anthropic_claude',
    ai_used: $json.ai_used === true,
    ai_parse_status: $json.ai_parse_status || null,
    ai_parse_error: $json.ai_parse_error || null,
    ai_suggestions_json: JSON.stringify($json.ai_suggestions || null),
    ai_raw_response: $json.ai_raw_response || null,
    human_review_required: true,
    legal_approval_allowed: false,
    ocr_status: ocr.status || null,
    ocr_engine: ocr.engine || null,
    ocr_language: ocr.language || null,
    ocr_text_char_count: ocr.text_char_count || 0,
    ocr_completed: ocr.ocr_used === true,
    review_payload_json: JSON.stringify($json.review_payload),
  },
};
